Actionscript.script:
var _this = this;

this.user_id = null;
this.social = false;
if (this.show === undefined) this.show = "Everybody";
if (this.period === undefined) this.period = "A";
if (this.board_id === undefined) this.board_id = 0;

this.setPropsForShow = function() {
	if (NGIO.hasUser() && (this.show === "My Best" || this.show === "Friends")) {
		this.user_id = NGIO.getUser().id;
		this.social = this.show === "Friends";
		if (this.show === "My Best") this.period = "A";
	} else {
		this.user_id = null;
		this.social = false;
		this.show = "Everyone";
	}
}

if (this.onClose === undefined) {
	this.onClose = function() {};
}

this.dispose = function() {
	_this.onClose = null;
	NGIO.scoreboardComponent = null;
}

this.onUnload = this.dispose;

this.doOnClose = function():Void {
	this._visible = false;
	this.onClose();
}

this.init = function() {

	NGIO.scoreboardComponent = this;

	this.setPropsForShow();

	// get a proper period value
	switch(this.period.toLowerCase()) {

		case 'd':
		case 'day':
		case 'today':
			this.period = 'D';
			break;

		case 'w':
		case 'week':
			this.period = 'W';
			break;

		case 'm':
		case 'month':
			this.period = 'M';
			break;

		case 'y':
		case 'year':
			this.period = 'Y';
			break;

		default:
			this.period = 'A';
			break;
	}

	var found = false;

	// if no board was provided, use the first one we can find
	if (this.board_id < 1) {
		this.board_id = NGIO.getScoreBoards()[0].id;
		found = this.board_id !== undefined;

	// otherwise, make sue the provided id actually exists
	} else {
		for (var i=0; i<NGIO.getScoreBoards().length; i++) {
			if (NGIO.getScoreBoards()[i].id === this.board_id) {
				found = true;
				break;
			}
		}
	}

	if (!this.tag) this.tag = null;

	// hopefully we found a board to load...
	if (found) {
		this.refreshBoard();
	} else {
		this.error = "Error: could not find any scoreboards with id "+this.board_id;
		this.gotoAndStop('error');
	}
}

// call this to refresh to board using the set properties or any replacement values
this.refreshBoard = function(props) {

	// we can skip all of this if there's no properties passed
	if (props !== undefined) {

		var changed = false;

		if (props.show !== undefined && props.show !== this.show) {
			this.show = props.show;
			this.setPropsForShow();
			changed = true;
		}
		// apply any new properties
		if (props.board_id !== undefined && props.board_id !== this.board_id) {
			this.board_id = props.board_id;
			changed = true;
		}
		if (props.period !== undefined && props.period !== this.period) {
			this.period = props.period;
			changed = true;
		}
		if (props.tag !== undefined && props.tag !== this.tag) {
			this.tag = props.tag;
			changed = true;
		}

		// if nothing was actually changed, do nothing
		if (!changed) return;
	}

	// if we get here, load the new scores and re-draw the list
	this.gotoAndStop('load');
}

// when a new set of scores is loaded, go to the display frame
this.onScoresLoaded = function(scores) {
	this.scores = scores;
	if (!NGIO.hasUser()) this.gotoAndStop('display_logged_out');
	else if (this.show === "My Best") this.gotoAndStop('display_my_best');
	else this.gotoAndStop('display');
}

// check for dependencies, and if we have everything, initialize the board
if (!NGIO) {
	this.error = 'Error: Unable to access NGIO library!';
	this.gotoAndStop('error');
} else if (NGIO.getScoreBoards() === null) {
	this.error = 'Error: Scoreboards have not been loaded yet!';
	this.gotoAndStop('error');
} else if (NGIO.getScoreBoards().length < 1) {
	this.error = 'Error: It appears this game does not have any scoreboards set up';
	this.gotoAndStop('error');
} else {
	this.init();
}

stop();

// store a reference to the selected board's model object
function loadScores() {
	this.scoreBoard = NGIO.getScoreBoard(this.board_id);

	// or toss an error if the board isn't loaded
	if (!this.scoreBoard) {
		this.error = "Could not find scoreboard with ID "+this.board_id;
		this.gotoAndStop('error');
	}

	// By default we're only going to load the top 10 scores
	var scoreFilters:Object = {limit: 10};

	// set our actual filter values for the comoonent
	scoreFilters.user_id = this.user_id;
	scoreFilters.social = this.social;
	scoreFilters.period = this.period;

	if (this.tag) scoreFilters.tag = this.tag;

	// load the scores from the server.  When this is done, we'll end up in the 'display' frame
	this.scoreBoard.getScores(
		scoreFilters,
		this.onScoresLoaded,
		this
	);
}

loadScores.call(this);
